namespace optiling {

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    ArgmaxOverADimensionCustomTilingData tiling;

    const gert::Shape *x_shape = context->GetInputShape(0);
    const gert::Shape &origin = x_shape->GetOriginShape();

    const int32_t rank = static_cast<int32_t>(origin.GetDimNum());
    if (rank <= 0) {
        return ge::GRAPH_FAILED;
    }

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const int32_t *attrDim = attrs->GetAttrPointer<int32_t>(0);

    int32_t dim = (attrDim != nullptr) ? *attrDim : 0;
    if (dim < 0) dim += rank;
    if (dim < 0 || dim >= rank) {
        return ge::GRAPH_FAILED;
    }

    uint64_t outer64 = 1, inner64 = 1, axisLen64 = static_cast<uint64_t>(origin.GetDim(dim));
    for (int32_t i = 0; i < dim; ++i) outer64 *= static_cast<uint64_t>(origin.GetDim(i));
    for (int32_t i = dim + 1; i < rank; ++i) inner64 *= static_cast<uint64_t>(origin.GetDim(i));

    // Clamp to 32-bit for kernel fields (reasonable for tensor sizes)
    uint32_t outer = static_cast<uint32_t>(outer64);
    uint32_t inner = static_cast<uint32_t>(inner64);
    uint32_t axisLen = static_cast<uint32_t>(axisLen64);

    // Choose blockDim based on outer parallelism
    uint32_t blockDim = outer;
    if (blockDim == 0) blockDim = 1;
    if (blockDim > 32u) blockDim = 32u;
    if (blockDim < 1u) blockDim = 1u;
    context->SetBlockDim(blockDim);

    tiling.set_outer(outer);
    tiling.set_axisLen(axisLen);
    tiling.set_inner(inner);
    tiling.set_blockDim(blockDim);
    tiling.set_dim(dim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

} // namespace optiling

namespace ge {
static ge::graphStatus InferShape(gert::InferShapeContext *context)
{
    const gert::Shape *x_shape = context->GetInputShape(0);
    const gert::Shape &origin = x_shape->GetOriginShape();

    const int32_t rank = static_cast<int32_t>(origin.GetDimNum());
    if (rank <= 0) {
        return GRAPH_FAILED;
    }

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const int32_t *attrDim = attrs->GetAttrPointer<int32_t>(0);

    int32_t dim = (attrDim != nullptr) ? *attrDim : 0;
    if (dim < 0) dim += rank;
    if (dim < 0 || dim >= rank) {
        return GRAPH_FAILED;
    }

    // Build output shape = input shape with axis 'dim' removed
    gert::Shape *y_shape = context->GetOutputShape(0);
    std::vector<int64_t> out_dims;
    out_dims.reserve(static_cast<size_t>(rank - 1));
    for (int32_t i = 0; i < rank; ++i) {
        if (i == dim) continue;
        out_dims.push_back(origin.GetDim(i));
    }
    y_shape->SetDimNum(static_cast<uint32_t>(out_dims.size()));
    for (size_t i = 0; i < out_dims.size(); ++i) {
        y_shape->SetDim(i, out_dims[i]);
    }
    return GRAPH_SUCCESS;
}

